#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e3 + 5;
int m, n, a[MAXN], f[MAXN][MAXN];
int main(void)
{
	scanf("%d%d", &n, &m);
	for (int i = 1; i <= n; ++i)scanf("%d", a + i);
	for (int i = 1; i <= n; ++i)
		for (int j = 1; j <= m; ++j)
		{
			if (j == a[i])f[i][j] = f[i - 1][j] + 1;
			if (j > a[i])f[i][j] = f[i - 1][j] + f[i - 1][j - a[i]];
			if (j < a[i])f[i][j] = f[i - 1][j];
		}
	printf("%d", f[n][m]);
	return false;
}
